    from scipy import ndimage
    grid = np.array(grid)
    H, W = grid.shape

    # Find rectangular frames
    def find_rect_frames(grid):
        H, W = grid.shape
        frames = []
        for r1 in range(H-2):
            c = 0
            while c < W:
                color = int(grid[r1, c])
                c_end = c
                while c_end + 1 < W and grid[r1, c_end + 1] == color:
                    c_end += 1
                seg_len = c_end - c + 1
                if seg_len >= 3:
                    c1, c2 = c, c_end
                    for r2 in range(r1 + 2, H):
                        if all(grid[r2, cc] == color for cc in range(c1, c2+1)):
                            if all(grid[rr, c1] == color for rr in range(r1, r2+1)):
                                if all(grid[rr, c2] == color for rr in range(r1, r2+1)):
                                    interior = grid[r1+1:r2, c1+1:c2]
                                    if interior.size > 0 and not np.all(interior == color):
                                        frames.append((r1, c1, r2, c2, color))
                c = c_end + 1
        frames.sort(key=lambda f: (f[2]-f[0])*(f[3]-f[1]), reverse=True)
        result = []
        for f in frames:
            r1, c1, r2, c2, color = f
            is_sub = False
            for rf in result:
                rr1, cc1, rr2, cc2, _ = rf
                if rr1 <= r1 and cc1 <= c1 and rr2 >= r2 and cc2 >= c2:
                    is_sub = True
                    break
            if not is_sub:
                result.append(f)
        return result

    frames = find_rect_frames(grid)

    # For each frame, extract interior and find background color (most common)
    frame_data = []
    for r1, c1, r2, c2, border_color in frames:
        interior = grid[r1+1:r2, c1+1:c2].copy()
        # Background is the most common color
        vals, counts = np.unique(interior, return_counts=True)
        bg_color = int(vals[np.argmax(counts)])
        # Non-background colors
        non_bg = set(int(v) for v in vals if v != bg_color)
        # Non-background cell count
        non_bg_count = int(np.sum(interior != bg_color))
        frame_data.append({
            'r1': r1, 'c1': c1, 'r2': r2, 'c2': c2,
            'border': int(border_color), 'bg': bg_color,
            'non_bg_colors': non_bg, 'non_bg_count': non_bg_count,
            'interior': interior
        })

