    shared_colors = frame_data[0]['non_bg_colors'] & frame_data[1]['non_bg_colors']

    # Template has more non-bg cells, target has fewer
    if frame_data[0]['non_bg_count'] > frame_data[1]['non_bg_count']:
        template, target = frame_data[0], frame_data[1]
    else:
