    t_int = template['interior']
    non_bg_mask = t_int != template['bg']
    labeled, num = ndimage.label(non_bg_mask)

    # For each component, find which marker color it contains
    patterns = {}  # marker_color -> list of (dr, dc, color) offsets
    for comp_id in range(1, num + 1):
        comp_cells = np.argwhere(labeled == comp_id)
        # Find marker color in this component
        marker_color = None
        for r, c in comp_cells:
            if int(t_int[r, c]) in shared_colors:
                marker_color = int(t_int[r, c])
                marker_r, marker_c = int(r), int(c)
                break

        if marker_color is not None:
            # Record pattern relative to marker
            offsets = []
            for r, c in comp_cells:
                dr, dc = int(r) - marker_r, int(c) - marker_c
                offsets.append((dr, dc, int(t_int[r, c])))

            if marker_color not in patterns:
                patterns[marker_color] = offsets

    # Build output: target rectangle with patterns stamped
    tr1, tc1, tr2, tc2 = target['r1'], target['c1'], target['r2'], target['c2']
    output = grid[tr1:tr2+1, tc1:tc2+1].copy()

    # Find marker positions in target interior
    t_target = target['interior']
    for r in range(t_target.shape[0]):
        for c in range(t_target.shape[1]):
            cell_color = int(t_target[r, c])
            if cell_color in shared_colors and cell_color in patterns:
                # Stamp pattern at this position
                for dr, dc, color in patterns[cell_color]:
                    out_r = r + 1 + dr  # +1 for border
                    out_c = c + 1 + dc  # +1 for border
                    if 0 <= out_r < output.shape[0] and 0 <= out_c < output.shape[1]:
                        output[out_r, out_c] = color

    return output.tolist()

