        print(f"  Result shape: {result_arr.shape}, Expected shape: {expected_arr.shape}")
        if result_arr.shape == expected_arr.shape:
            diff = result_arr != expected_arr
            print(f"  Differences at: {np.argwhere(diff).tolist()}")

